import React, { useState } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

interface EmojiDetectiveProps {
  onComplete: () => void;
}

const EmojiDetective: React.FC<EmojiDetectiveProps> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [showFeedback, setShowFeedback] = useState<'none' | 'correct' | 'wrong'>('none');

  const currentWord = WORD_LIST[currentIndex];
  const options = React.useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id);
    const shuffled = [...others].sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...shuffled, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const handleSelect = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      setShowFeedback('correct');
      setScore(s => s + 1);
      setTimeout(() => {
        if (currentIndex < WORD_LIST.length - 1) {
          setCurrentIndex(c => c + 1);
          setShowFeedback('none');
        } else {
          onComplete();
        }
      }, 1000);
    } else {
      setShowFeedback('wrong');
      setTimeout(() => setShowFeedback('none'), 1000);
    }
  };

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-8">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Bulbasaur)} className="w-20 h-20" alt="Bulbasaur" />
        <h2 className="text-4xl font-bold text-green-700">Emoji Detective 🔍</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          {currentIndex + 1} / {WORD_LIST.length}
        </div>
      </div>

      <div className="mb-12">
        <div className="text-9xl mb-4 animate-bounce">{currentWord.emoji}</div>
        <div className="text-4xl font-bold text-gray-700">({currentWord.cn})</div>
      </div>

      <div className="grid grid-cols-2 gap-6">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => handleSelect(opt)}
            className="p-6 text-3xl font-bold bg-white hover:bg-yellow-100 transition-all crayon-border transform hover:-translate-y-1"
          >
            {opt.en}
          </button>
        ))}
      </div>

      {showFeedback !== 'none' && (
        <div className={`fixed inset-0 flex items-center justify-center pointer-events-none z-50`}>
          <div className={`text-9xl font-bold ${showFeedback === 'correct' ? 'text-green-500' : 'text-red-500'} drop-shadow-lg`}>
            {showFeedback === 'correct' ? '✔️ GREAT!' : '❌ OOPS!'}
          </div>
        </div>
      )}
    </div>
  );
};

export default EmojiDetective;

import React, { useState, useEffect } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

interface MatchingGameProps {
  onComplete: () => void;
}

const MatchingGame: React.FC<MatchingGameProps> = ({ onComplete }) => {
  const [rounds, setRounds] = useState(0);
  const [selectedEn, setSelectedEn] = useState<string | null>(null);
  const [selectedCn, setSelectedCn] = useState<string | null>(null);
  const [matchedIds, setMatchedIds] = useState<string[]>([]);

  const [currentSet, setCurrentSet] = useState<any[]>([]);

  useEffect(() => {
    const start = rounds * 5;
    const set = WORD_LIST.slice(start, start + 5);
    if (set.length === 0) {
      onComplete();
      return;
    }
    const enSide = [...set].sort(() => 0.5 - Math.random());
    const cnSide = [...set].sort(() => 0.5 - Math.random());
    setCurrentSet(set);
    setEnOptions(enSide);
    setCnOptions(cnSide);
  }, [rounds]);

  const [enOptions, setEnOptions] = useState<any[]>([]);
  const [cnOptions, setCnOptions] = useState<any[]>([]);

  useEffect(() => {
    if (selectedEn && selectedCn) {
      if (selectedEn === selectedCn) {
        setMatchedIds(prev => [...prev, selectedEn!]);
        setSelectedEn(null);
        setSelectedCn(null);
      } else {
        setTimeout(() => {
          setSelectedEn(null);
          setSelectedCn(null);
        }, 500);
      }
    }
  }, [selectedEn, selectedCn]);

  useEffect(() => {
    if (matchedIds.length > 0 && matchedIds.length === currentSet.length) {
      if ((rounds + 1) * 5 >= WORD_LIST.length) {
        onComplete();
      } else {
        setTimeout(() => {
          setRounds(r => r + 1);
          setMatchedIds([]);
        }, 1000);
      }
    }
  }, [matchedIds, currentSet]);

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-8">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Charmander)} className="w-20 h-20" alt="Charmander" />
        <h2 className="text-4xl font-bold text-orange-600">Matching Adventure 🎴</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          Set {rounds + 1} / {Math.ceil(WORD_LIST.length / 5)}
        </div>
      </div>

      <div className="flex gap-12 justify-center">
        <div className="flex flex-col gap-4 w-1/2">
          {enOptions.map(w => (
            <button
              key={w.id}
              disabled={matchedIds.includes(w.id)}
              onClick={() => setSelectedEn(w.id)}
              className={`p-4 text-2xl font-bold crayon-border transition-all ${
                matchedIds.includes(w.id) ? 'bg-green-200 opacity-50' : 
                selectedEn === w.id ? 'bg-blue-300 transform scale-105' : 'bg-white hover:bg-blue-50'
              }`}
            >
              {w.en}
            </button>
          ))}
        </div>
        <div className="flex flex-col gap-4 w-1/2">
          {cnOptions.map(w => (
            <button
              key={w.id}
              disabled={matchedIds.includes(w.id)}
              onClick={() => setSelectedCn(w.id)}
              className={`p-4 text-2xl font-bold crayon-border transition-all ${
                matchedIds.includes(w.id) ? 'bg-green-200 opacity-50' : 
                selectedCn === w.id ? 'bg-pink-300 transform scale-105' : 'bg-white hover:bg-pink-50'
              }`}
            >
              {w.cn}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MatchingGame;

import React, { useState, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

interface SpellingBeeProps {
  onComplete: () => void;
}

const SpellingBee: React.FC<SpellingBeeProps> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState<string[]>([]);
  const currentWord = WORD_LIST[currentIndex].en.toLowerCase();

  const letterOptions = useMemo(() => {
    // Collect letters, include spaces but treat spaces specially
    const letters = currentWord.split('').filter(l => l !== ' ');
    // Add some random letters
    const extras = 'abcdefghijklmnopqrstuvwxyz'.split('').sort(() => 0.5 - Math.random()).slice(0, 4);
    return [...letters, ...extras].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const handleLetterClick = (char: string) => {
    // If the next expected character in currentWord is a space, add it automatically
    let nextInput = [...input];
    const targetWithSpaces = currentWord.split('');

    // Check if we need to auto-insert space
    if (targetWithSpaces[nextInput.length] === ' ') {
      nextInput.push(' ');
    }

    nextInput.push(char);
    setInput(nextInput);

    // Check if correct so far
    const currentAttempt = nextInput.join('');
    if (currentAttempt === currentWord) {
      setTimeout(() => {
        if (currentIndex < WORD_LIST.length - 1) {
          setCurrentIndex(c => c + 1);
          setInput([]);
        } else {
          onComplete();
        }
      }, 800);
    }
  };

  const handleCancel = (index: number) => {
    // If we cancel, just remove from that index onwards
    setInput(prev => prev.slice(0, index));
  };

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-8">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Squirtle)} className="w-20 h-20" alt="Squirtle" />
        <h2 className="text-4xl font-bold text-blue-600">Spelling Bee 🐝</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          {currentIndex + 1} / {WORD_LIST.length}
        </div>
      </div>

      <div className="mb-8">
        <div className="text-4xl font-bold text-gray-700 mb-4">{WORD_LIST[currentIndex].cn}</div>
        <div className="text-6xl mb-4">{WORD_LIST[currentIndex].emoji}</div>
      </div>

      <div className="flex flex-wrap justify-center gap-2 mb-12 min-h-[80px]">
        {currentWord.split('').map((char, idx) => {
          const isSpace = char === ' ';
          const filled = input[idx];
          return (
            <div
              key={idx}
              onClick={() => filled && handleCancel(idx)}
              className={`w-12 h-16 flex items-center justify-center text-4xl font-bold crayon-border cursor-pointer transition-all ${
                isSpace ? 'border-none bg-transparent w-6' : 
                filled ? 'bg-yellow-200 animate-wiggle' : 'bg-gray-100'
              }`}
            >
              {filled !== ' ' ? filled : ''}
            </div>
          );
        })}
      </div>

      <div className="flex flex-wrap justify-center gap-4">
        {letterOptions.map((l, idx) => (
          <button
            key={idx}
            onClick={() => handleLetterClick(l)}
            className="w-16 h-16 bg-white text-3xl font-bold crayon-border hover:bg-blue-100 transform active:scale-90"
          >
            {l}
          </button>
        ))}
      </div>

      <p className="mt-8 text-gray-500 italic">Click a letter in the word to undo!</p>
    </div>
  );
};

export default SpellingBee;

