import React, { useState, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

const BubblePop: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);

  const currentWord = WORD_LIST[currentIndex];

  const options = useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id).sort(() => 0.5 - Math.random()).slice(0, 5);
    return [...others, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const pokemonRewards = useMemo(() => {
    const ids = Object.values(POKEMON_IDS);
    return ids.sort(() => 0.5 - Math.random());
  }, []);

  const handlePop = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      setCorrectCount(c => c + 1);
      if (currentIndex < WORD_LIST.length - 1) {
        setCurrentIndex(c => c + 1);
      } else {
        onComplete();
      }
    }
  };

  return (
    <div className="text-center p-4 min-h-[600px] relative overflow-hidden bg-blue-50/50">
      {/* Ocean Decorations */}
      <div className="absolute top-10 left-10 text-4xl animate-bounce">🐠</div>
      <div className="absolute bottom-20 right-10 text-4xl animate-pulse">🐙</div>
      <div className="absolute top-1/2 left-4 text-4xl animate-wiggle">🌿</div>

      <div className="flex justify-between items-center mb-8 relative z-10">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Squirtle)} className="w-20 h-20" alt="Squirtle" />
        <h2 className="text-4xl font-bold text-blue-800">Bubble Pop 🫧</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          Score: {correctCount}
        </div>
      </div>

      <div className="mb-12 relative z-10">
        <p className="text-3xl text-gray-600 mb-2 font-bold">Find the English for:</p>
        <p className="text-5xl font-bold text-blue-900">{currentWord.cn}</p>
      </div>

      <div className="grid grid-cols-3 grid-rows-2 gap-8 mb-12 justify-items-center relative z-10">
        {options.map((opt, i) => (
          <button
