import React, { useState, useEffect } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

const GRID_SIZE = 12;

const WordSearch: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [grid, setGrid] = useState<string[][]>([]);
  const [foundWords, setFoundWords] = useState<string[]>([]);
  const [currentSelection, setCurrentSelection] = useState<[number, number][]>([]);

  // Game limits to 8 words per session for searchability
  const wordsToFind = useMemo(() => WORD_LIST.slice(0, 8).map(w => w.en.toLowerCase().replace(/\s/g, '')), []);

  useEffect(() => {
    generateGrid();
  }, []);

  const generateGrid = () => {
    let newGrid = Array(GRID_SIZE).fill(null).map(() => Array(GRID_SIZE).fill(''));

    wordsToFind.forEach(word => {
      let placed = false;
      while (!placed) {
        const direction = Math.random() > 0.5 ? 'H' : 'V';
        const row = Math.floor(Math.random() * (direction === 'H' ? GRID_SIZE : GRID_SIZE - word.length));
        const col = Math.floor(Math.random() * (direction === 'V' ? GRID_SIZE : GRID_SIZE - word.length));

        let canPlace = true;
        for (let i = 0; i < word.length; i++) {
          const r = direction === 'V' ? row + i : row;
          const c = direction === 'H' ? col + i : col;
          if (newGrid[r][c] !== '' && newGrid[r][c] !== word[i]) {
            canPlace = false;
            break;
          }
        }

        if (canPlace) {
          for (let i = 0; i < word.length; i++) {
            const r = direction === 'V' ? row + i : row;
            const c = direction === 'H' ? col + i : col;
            newGrid[r][c] = word[i];
          }
          placed = true;
        }
      }
    });

    for (let r = 0; r < GRID_SIZE; r++) {
      for (let c = 0; c < GRID_SIZE; c++) {
        if (newGrid[r][c] === '') {
          newGrid[r][c] = String.fromCharCode(97 + Math.floor(Math.random() * 26));
        }
      }
    }
    setGrid(newGrid);
  };

  const handleCellClick = (r: number, c: number) => {
    const newSelection = [...currentSelection, [r, c] as [number, number]];
    setCurrentSelection(newSelection);

    const word = newSelection.map(([r, c]) => grid[r][c]).join('');
    if (wordsToFind.includes(word) && !foundWords.includes(word)) {
      setFoundWords([...foundWords, word]);
      setCurrentSelection([]);
    } else if (newSelection.length > 15) {
      setCurrentSelection([]);
    }
  };

  const autoFind = (word: string) => {
    if (!foundWords.includes(word)) {
      setFoundWords([...foundWords, word]);
    }
  };

  useEffect(() => {
    if (foundWords.length === wordsToFind.length) {
      setTimeout(onComplete, 1000);
    }
  }, [foundWords]);

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-6">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Meowth || 52)} className="w-20 h-20" alt="Meowth" />
        <h2 className="text-4xl font-bold text-yellow-700">Word Search 🔍</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          {foundWords.length} / {wordsToFind.length}
        </div>
      </div>

      <div className="flex gap-8">
        <div className="grid grid-cols-12 gap-1 bg-white p-2 crayon-border shadow-inner">
          {grid.map((row, r) => row.map((char, c) => {
            const isSelected = currentSelection.some(([sr, sc]) => sr === r && sc === c);
            return (
              <div
                key={`${r}-${c}`}
                onClick={() => handleCellClick(r, c)}
                className={`w-8 h-8 md:w-10 md:h-10 flex items-center justify-center text-xl font-bold cursor-pointer transition-colors ${
                  isSelected ? 'bg-yellow-400' : 'bg-transparent hover:bg-gray-100'
                }`}
              >
                {char}
              </div>
            );
          }))}
        </div>

        <div className="flex flex-col gap-2 text-left">
          <p className="font-bold text-xl mb-2">Find these words:</p>
          {wordsToFind.map(w => (
            <button
              key={w}
              onClick={() => autoFind(w)}
              className={`text-lg font-bold p-2 text-left transition-all ${
                foundWords.includes(w) ? 'line-through text-green-500 opacity-50' : 'text-blue-600 hover:text-blue-800'
              }`}
            >
              {foundWords.includes(w) ? '✔️' : '🔍'} {w}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default WordSearch;

function useMemo<T>(factory: () => T, deps: any[]): T {
  return React.useMemo(factory, deps);
}

import React, { useState, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

const PokemonBattle: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [playerHP, setPlayerHP] = useState(100);
  const [enemyHP, setEnemyHP] = useState(100);
  const [isAttacking, setIsAttacking] = useState(false);

  const currentWord = WORD_LIST[currentIndex];

  const options = useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id).sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...others, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const handleAttack = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      setIsAttacking(true);
      setEnemyHP(prev => Math.max(0, prev - 20));
      setTimeout(() => {
        setIsAttacking(false);
        if (enemyHP <= 20) {
          onComplete();
        } else if (currentIndex < WORD_LIST.length - 1) {
          setCurrentIndex(c => c + 1);
        } else {
          onComplete();
        }
      }, 1000);
    } else {
      setPlayerHP(prev => Math.max(0, prev - 10));
    }
  };

  return (
    <div className="text-center p-4 min-h-[500px] flex flex-col justify-between">
      <h2 className="text-4xl font-bold text-red-600 mb-4">Pokemon Battle! ⚔️</h2>

