import React, { useState, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

const BubblePop: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [correctCount, setCorrectCount] = useState(0);
  const [rewardHistory, setRewardHistory] = useState<number[]>([]);

  const currentWord = WORD_LIST[currentIndex];

  const options = useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id).sort(() => 0.5 - Math.random()).slice(0, 5);
    return [...others, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const pokemonPool = useMemo(() => Object.values(POKEMON_IDS).sort(() => 0.5 - Math.random()), []);

  const handlePop = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      setCorrectCount(c => c + 1);
      setRewardHistory(prev => [...prev, pokemonPool[prev.length % pokemonPool.length]]);
      if (currentIndex < WORD_LIST.length - 1) {
        setCurrentIndex(c => c + 1);
      } else {
        onComplete();
      }
    }
  };

  return (
    <div className="text-center p-4 min-h-[650px] relative overflow-hidden bg-blue-50/80 rounded-3xl">
      {/* Background Ocean Elements */}
      <div className="absolute top-10 left-10 text-5xl animate-float">🐢</div>
      <div className="absolute top-20 right-20 text-5xl animate-float" style={{animationDelay: '1.5s'}}>🐠</div>
      <div className="absolute bottom-40 left-20 text-5xl animate-float opacity-40">🌿</div>
      <div className="absolute bottom-20 right-10 text-6xl animate-pulse">🐙</div>

      <div className="flex justify-between items-center mb-8 relative z-10 px-4">
        <div className="bg-white/90 p-2 rounded-full crayon-border">
          <img src={POKEMON_SPRITES(POKEMON_IDS.Squirtle)} className="w-16 h-16" alt="Squirtle" />
        </div>
        <h2 className="text-5xl font-bold text-blue-600 drop-shadow-sm">Bubble Pop 🫧</h2>
        <div className="text-3xl font-bold bg-white px-6 py-2 crayon-border text-pink-500 shadow-sm">
          {correctCount}
        </div>
      </div>

      <div className="mb-10 relative z-10">
        <p className="text-2xl text-blue-400 font-bold mb-1">Pick the English for:</p>
        <p className="text-5xl font-bold text-blue-900 drop-shadow-sm">{currentWord.cn}</p>
      </div>

      {/* 2 Rows, 3 Columns Fixed Grid */}
      <div className="grid grid-cols-3 gap-8 mb-10 justify-items-center relative z-10 px-10">
        {options.map((opt, i) => (
          <button
            key={`${currentIndex}-${i}`}
            onClick={() => handlePop(opt)}
            className="bubble w-36 h-36 flex items-center justify-center text-2xl font-bold text-blue-700 hover:scale-110 hover:bg-white/60 transition-all active:scale-90 shadow-xl p-4 text-center leading-tight"
            style={{ animation: `wiggle ${3 + i * 0.4}s ease-in-out infinite` }}
          >
            {opt.en}
          </button>
        ))}
      </div>

      {/* Shell Rewards Section */}
      <div className="relative z-10 flex flex-col items-center mt-4">
        <div className="relative">
          <div className="text-8xl mb-2 drop-shadow-lg">🐚</div>
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 flex flex-wrap gap-1 justify-center max-w-[200px]">
             {rewardHistory.map((pId, idx) => (
               <img 
                 key={idx} 
                 src={POKEMON_SPRITES(pId)} 
                 className="w-10 h-10 animate-bounce"
                 style={{ animationDelay: `${idx * 0.1}s` }}
                 alt="reward" 
               />
             ))}
          </div>
        </div>
        <p className="text-xl font-bold text-blue-800 mt-2">Shell Collection ✨</p>
      </div>
    </div>
  );
};

