import React, { useState } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';

interface EmojiDetectiveProps {
  onComplete: () => void;
}

const EmojiDetective: React.FC<EmojiDetectiveProps> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [showFeedback, setShowFeedback] = useState<'none' | 'correct' | 'wrong'>('none');

  const currentWord = WORD_LIST[currentIndex];
  const options = React.useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id);
    const shuffled = [...others].sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...shuffled, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord, currentIndex]);

  const handleSelect = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      setShowFeedback('correct');
      setTimeout(() => {
        if (currentIndex < WORD_LIST.length - 1) {
          setCurrentIndex(c => c + 1);
          setShowFeedback('none');
        } else {
          onComplete();
        }
      }, 1000);
    } else {
      setShowFeedback('wrong');
      setTimeout(() => setShowFeedback('none'), 1000);
    }
  };

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-10 px-4">
        <div className="bg-green-100 p-2 rounded-full animate-float crayon-border shadow-md">
           <img src={POKEMON_SPRITES(POKEMON_IDS.Bulbasaur)} className="w-16 h-16" alt="Bulbasaur" />
        </div>
        <h2 className="text-5xl font-bold text-green-600 drop-shadow-sm">Emoji Detective 🔍</h2>
        <div className="text-3xl font-bold bg-white px-6 py-2 crayon-border text-pink-400">
          {currentIndex + 1} / {WORD_LIST.length}
        </div>
      </div>

      <div className="mb-10 p-8 bg-yellow-50/50 rounded-full inline-block relative">
        <div className="text-[120px] mb-4 animate-float filter drop-shadow-lg">{currentWord.emoji}</div>
        <div className="text-4xl font-bold text-gray-500 bg-white/80 px-8 py-2 rounded-full shadow-sm crayon-border">{currentWord.cn}</div>
        <div className="absolute -top-4 -right-4 text-5xl animate-bounce">✨</div>
      </div>

      <div className="grid grid-cols-2 gap-8 max-w-2xl mx-auto">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => handleSelect(opt)}
            className="p-8 text-3xl font-bold bg-white text-gray-700 hover:bg-pink-100 hover:text-pink-700 transition-all crayon-button shadow-lg transform hover:-translate-y-2 active:scale-95"
          >
            {opt.en}
          </button>
        ))}
      </div>

      {showFeedback !== 'none' && (
        <div className={`fixed inset-0 flex items-center justify-center pointer-events-none z-50 bg-white/40 backdrop-blur-sm`}>
          <div className={`text-9xl font-bold ${showFeedback === 'correct' ? 'text-green-500' : 'text-red-400'} drop-shadow-2xl animate-wiggle`}>
            {showFeedback === 'correct' ? '🌟 YES!' : '🎀 OOPS!'}
          </div>
        </div>
      )}
    </div>
  );
};

