export const playSound = (type: 'correct' | 'wrong') => {
  const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
  if (!AudioContextClass) return;

  const ctx = new AudioContextClass();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();

  if (type === 'correct') {
    osc.type = 'sine';
    osc.frequency.setValueAtTime(523.25, ctx.currentTime); // C5
    osc.frequency.exponentialRampToValueAtTime(1046.50, ctx.currentTime + 0.1); // C6
    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);
  } else {
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(150, ctx.currentTime); 
    osc.frequency.linearRampToValueAtTime(50, ctx.currentTime + 0.2); 
    gain.gain.setValueAtTime(0.1, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.3);
  }

  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start();
  osc.stop(ctx.currentTime + 0.3);
};

import React, { useState, useEffect, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';
import { playSound } from '../utils/sounds';

interface TugOfWarProps {
  onComplete: () => void;
}

const TugOfWar: React.FC<TugOfWarProps> = ({ onComplete }) => {
  const [round, setRound] = useState(0);
  const [team1Progress, setTeam1Progress] = useState(0); // 0 to 5
  const [currentIndex, setCurrentIndex] = useState(0);
  const [feedback, setFeedback] = useState<'none' | 'correct' | 'wrong'>('none');

  // We play in groups of 5 words
  const roundWords = useMemo(() => {
    return WORD_LIST.slice(round * 5, (round * 5) + 5);
  }, [round]);

  const currentWord = roundWords[currentIndex];

  const options = useMemo(() => {
    if (!currentWord) return [];
    const others = WORD_LIST.filter(w => w.id !== currentWord.id).sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...others, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const handleSelect = (wordId: string) => {
    if (wordId === currentWord.id) {
      playSound('correct');
      setFeedback('correct');
      setTeam1Progress(p => Math.min(p + 1, 5));
      setTimeout(() => {
        setFeedback('none');
        if (currentIndex < roundWords.length - 1) {
          setCurrentIndex(i => i + 1);
        } else {
          // Finished the 5-word set
          if ((round + 1) * 5 >= WORD_LIST.length) {
            onComplete();
          } else {
            setRound(r => r + 1);
            setTeam1Progress(0);
            setCurrentIndex(0);
          }
        }
      }, 1000);
    } else {
      playSound('wrong');
      setFeedback('wrong');
      setTeam1Progress(p => Math.max(p - 1, 0)); // Pull back if wrong
      setTimeout(() => setFeedback('none'), 800);
    }
  };

  const ropeOffset = (team1Progress - 2.5) * 40; // Visual shift

  return (
    <div className="flex flex-col h-full select-none">
      <div className="text-center mb-6">
        <h2 className="text-4xl font-black text-blue-600 tracking-widest uppercase">Tug of War: Vocabulary</h2>
        <p className="text-gray-400 font-bold">First team to reach 5 pulls wins the round!</p>
