      <div className="flex flex-1 gap-4 items-stretch">
        {/* Team 1 Panel (Player) */}
        <div className="flex-1 bg-blue-50/50 rounded-3xl border-4 border-blue-400 flex flex-col items-center p-8 relative overflow-hidden">
          <div className="bg-blue-400 text-white px-8 py-2 rounded-full font-bold text-xl mb-8 shadow-md">TEAM 1</div>

          <div className="mb-10 text-center">
            <p className="text-3xl text-gray-500 font-bold mb-4 italic">Guess the English Word:</p>
            <div className="text-7xl font-black text-blue-600 bg-white px-10 py-6 rounded-3xl shadow-lg border-2 border-blue-100">
              {currentWord?.cn}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 w-full max-w-md">
            {options.map((opt) => (
              <button
                key={opt.id}
                onClick={() => handleSelect(opt.id)}
                className="p-6 text-2xl font-black bg-white border-2 border-blue-200 rounded-2xl hover:bg-blue-100 hover:border-blue-400 transition-all shadow-sm active:scale-95 text-gray-700"
              >
                {opt.en}
              </button>
            ))}
          </div>

          {feedback !== 'none' && (
             <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-6xl font-black ${feedback === 'correct' ? 'text-green-500' : 'text-red-500'} animate-bounce z-20`}>
                {feedback === 'correct' ? 'PULL!' : 'UH OH!'}
             </div>
          )}
        </div>

        {/* Competition Area (Center) */}
        <div className="w-96 bg-gray-50 rounded-3xl border-4 border-dashed border-gray-200 flex flex-col items-center justify-center p-4 relative overflow-hidden">
           {/* Scores */}
           <div className="absolute top-4 w-full flex justify-around px-4">
              <div className="bg-blue-100 text-blue-600 px-4 py-2 rounded-full font-black text-2xl border-2 border-blue-200">{team1Progress}</div>
              <div className="text-gray-400 font-black text-xl">VS</div>
              <div className="bg-red-100 text-red-600 px-4 py-2 rounded-full font-black text-2xl border-2 border-red-200">{5 - team1Progress}</div>
           </div>

           {/* Central Line */}
           <div className="absolute top-0 bottom-0 left-1/2 w-1 border-l-4 border-dashed border-gray-300 -translate-x-1/2"></div>

           {/* The Rope and Characters */}
           <div className="relative w-full h-96 flex items-center justify-center">
              {/* Rope */}
              <div className="absolute w-[150%] h-3 bg-amber-800 rounded-full shadow-md z-10" style={{ transform: `translateX(${ropeOffset}px)` }}>
                 {/* Rope Flag */}
