    switch (gameState.currentView) {
      case GameType.WORD_LIST:
        return <WordListView onStart={() => setGameState(prev => ({ ...prev, currentView: GameType.EMOJI_DETECTIVE }))} />;
      case GameType.EMOJI_DETECTIVE:
        return <EmojiDetective onComplete={() => completeGame(GameType.EMOJI_DETECTIVE)} />;
      case GameType.MATCHING:
        return <MatchingGame onComplete={() => completeGame(GameType.MATCHING)} />;
      case GameType.SPELLING_BEE:
        return <SpellingBee onComplete={() => completeGame(GameType.SPELLING_BEE)} />;
      case GameType.FILL_BLANKS:
        return <FillBlanks onComplete={() => completeGame(GameType.FILL_BLANKS)} />;
      case GameType.BUBBLE_POP:
        return <BubblePop onComplete={() => completeGame(GameType.BUBBLE_POP)} />;
      case GameType.WORD_SEARCH:
        return <WordSearch onComplete={() => completeGame(GameType.WORD_SEARCH)} />;
      case GameType.MIND_MEMORY:
        return <MindMemory onComplete={() => completeGame(GameType.MIND_MEMORY)} />;
      case GameType.RIDDLE_QUEST:
        return <RiddleQuest onComplete={() => completeGame(GameType.RIDDLE_QUEST)} />;
      case GameType.TUG_OF_WAR:
        return <TugOfWar onComplete={() => completeGame(GameType.TUG_OF_WAR)} />;
      case GameType.TREE_HOUSE:
        return (
          <TreeHouse
            unlockedIds={gameState.unlockedFurnitureIds}
            onNextGame={() => {
              const gameOrder = [
                GameType.EMOJI_DETECTIVE, GameType.MATCHING, GameType.SPELLING_BEE,
                GameType.FILL_BLANKS, GameType.BUBBLE_POP, GameType.WORD_SEARCH,
                GameType.MIND_MEMORY, GameType.RIDDLE_QUEST, GameType.TUG_OF_WAR
              ];
              const currentIndex = gameOrder.indexOf(gameState.completedGames[gameState.completedGames.length - 1]);
              const nextGame = gameOrder[currentIndex + 1] || GameType.WORD_LIST;
              setGameState(prev => ({ ...prev, currentView: nextGame }));
            }}
          />
        );
      default:
        return <WordListView onStart={() => setGameState(prev => ({ ...prev, currentView: GameType.EMOJI_DETECTIVE }))} />;
    }
  };

  return (
    <div className="min-h-screen p-4 flex flex-col items-center relative">
      <FloatingDecor />

      <header className="mb-8 text-center">
        <h1 className="text-6xl font-black text-pink-400 tracking-wider">
          Pikachu Adventure 🐾
        </h1>
        <p className="text-2xl text-blue-400 font-bold mt-2">Level 4 Vocabulary Quest</p>
      </header>

      <main className="w-full max-w-7xl bg-white p-8 md:p-12 wobbly-border relative mb-12 shadow-2xl h-[800px] overflow-hidden">
        {renderCurrentGame()}
      </main>

      <footer className="mt-auto flex gap-3 overflow-x-auto p-4 w-full max-w-7xl justify-center no-scrollbar">
        {Object.values(GameType).filter(t => t !== GameType.TREE_HOUSE).map((type) => (
          <button
            key={type}
            onClick={() => setGameState(prev => ({ ...prev, currentView: type }))}
            className={`px-5 py-2 text-lg font-bold rounded-full transition-all border-2 ${
              gameState.completedGames.includes(type) 
                ? 'bg-pink-100 text-pink-600 border-pink-300' 
                : 'bg-white text-gray-400 border-gray-200'
            } hover:border-pink-300 hover:text-pink-500`}
          >
            {type.toLowerCase().split('_').map(s => s.charAt(0).toUpperCase() + s.slice(1)).join(' ')}
          </button>
        ))}
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';
import { playSound } from '../utils/sounds';

interface EmojiDetectiveProps {
  onComplete: () => void;
}

const EmojiDetective: React.FC<EmojiDetectiveProps> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [showFeedback, setShowFeedback] = useState<'none' | 'correct' | 'wrong'>('none');

  const currentWord = WORD_LIST[currentIndex];
  const options = React.useMemo(() => {
    const others = WORD_LIST.filter(w => w.id !== currentWord.id);
    const shuffled = [...others].sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...shuffled, currentWord].sort(() => 0.5 - Math.random());
  }, [currentWord, currentIndex]);

  const handleSelect = (word: typeof currentWord) => {
    if (word.id === currentWord.id) {
      playSound('correct');
      setShowFeedback('correct');
      setTimeout(() => {
        if (currentIndex < WORD_LIST.length - 1) {
          setCurrentIndex(c => c + 1);
          setShowFeedback('none');
        } else {
          onComplete();
        }
      }, 800);
    } else {
      playSound('wrong');
      setShowFeedback('wrong');
      setTimeout(() => setShowFeedback('none'), 800);
    }
  };

  return (
    <div className="text-center">
      <div className="flex justify-between items-center mb-10 px-4">
        <h2 className="text-4xl font-black text-pink-400">Emoji Detective 🔍</h2>
        <div className="text-2xl font-bold bg-pink-50 text-pink-500 px-6 py-2 rounded-full border-2 border-pink-100">
          {currentIndex + 1} / {WORD_LIST.length}
        </div>
      </div>

      <div className="bg-gray-50 rounded-3xl p-12 mb-10 border-4 border-dashed border-gray-100 inline-block w-full max-w-lg">
          <div className="text-[140px] leading-none mb-6">{currentWord.emoji}</div>
          <div className="text-4xl font-bold text-gray-400 bg-white px-8 py-3 rounded-2xl shadow-sm inline-block">
              {currentWord.cn}
          </div>
      </div>

      <div className="grid grid-cols-2 gap-6 max-w-4xl mx-auto px-4">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => handleSelect(opt)}
            className="p-8 text-3xl font-bold text-gray-700 bg-white border-2 border-gray-100 rounded-2xl hover:border-pink-300 hover:text-pink-500 transition-all shadow-sm flex items-center justify-center h-32"
          >
            {opt.en}
          </button>
        ))}
      </div>

      {showFeedback !== 'none' && (
        <div className="fixed inset-0 flex items-center justify-center pointer-events-none z-50">
          <div className={`text-8xl font-black px-12 py-6 rounded-full shadow-2xl animate-bounce ${showFeedback === 'correct' ? 'bg-green-400 text-white' : 'bg-red-400 text-white'}`}>
            {showFeedback === 'correct' ? 'GREAT!' : 'OOPS!'}
          </div>
        </div>
      )}
    </div>
  );
};

export default EmojiDetective;

import React, { useState, useEffect } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';
import { playSound } from '../utils/sounds';

interface MatchingGameProps {
  onComplete: () => void;
}

const MatchingGame: React.FC<MatchingGameProps> = ({ onComplete }) => {
  const [rounds, setRounds] = useState(0);
  const [selectedEn, setSelectedEn] = useState<string | null>(null);
  const [selectedCn, setSelectedCn] = useState<string | null>(null);
  const [matchedIds, setMatchedIds] = useState<string[]>([]);

  const [currentSet, setCurrentSet] = useState<any[]>([]);
  const [enOptions, setEnOptions] = useState<any[]>([]);
  const [cnOptions, setCnOptions] = useState<any[]>([]);

  useEffect(() => {
    const start = rounds * 5;
    const set = WORD_LIST.slice(start, start + 5);
    if (set.length === 0) {
      onComplete();
      return;
    }
    const enSide = [...set].sort(() => 0.5 - Math.random());
    const cnSide = [...set].sort(() => 0.5 - Math.random());
    setCurrentSet(set);
    setEnOptions(enSide);
    setCnOptions(cnSide);
  }, [rounds]);

  useEffect(() => {
    if (selectedEn && selectedCn) {
      if (selectedEn === selectedCn) {
        playSound('correct');
        setMatchedIds(prev => [...prev, selectedEn!]);
        setSelectedEn(null);
        setSelectedCn(null);
      } else {
        playSound('wrong');
        setTimeout(() => {
          setSelectedEn(null);
          setSelectedCn(null);
        }, 500);
      }
    }
  }, [selectedEn, selectedCn]);

  useEffect(() => {
    if (matchedIds.length > 0 && matchedIds.length === currentSet.length) {
      if ((rounds + 1) * 5 >= WORD_LIST.length) {
        onComplete();
      } else {
        setTimeout(() => {
          setRounds(r => r + 1);
          setMatchedIds([]);
        }, 1000);
      }
    }
  }, [matchedIds, currentSet]);

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-8">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Charmander)} className="w-20 h-20" alt="Charmander" />
        <h2 className="text-4xl font-bold text-orange-600">Matching Adventure 🎴</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          Set {rounds + 1} / {Math.ceil(WORD_LIST.length / 5)}
        </div>
      </div>

      <div className="flex gap-12 justify-center">
        <div className="flex flex-col gap-4 w-1/2">
          {enOptions.map(w => (
            <button
              key={w.id}
              disabled={matchedIds.includes(w.id)}
              onClick={() => setSelectedEn(w.id)}
              className={`p-4 text-2xl font-bold crayon-border transition-all ${
                matchedIds.includes(w.id) ? 'bg-green-200 opacity-50' : 
                selectedEn === w.id ? 'bg-blue-300 transform scale-105' : 'bg-white hover:bg-blue-50'
              }`}
            >
              {w.en}
            </button>
          ))}
        </div>
        <div className="flex flex-col gap-4 w-1/2">
          {cnOptions.map(w => (
            <button
              key={w.id}
              disabled={matchedIds.includes(w.id)}
              onClick={() => setSelectedCn(w.id)}
              className={`p-4 text-2xl font-bold crayon-border transition-all ${
                matchedIds.includes(w.id) ? 'bg-green-200 opacity-50' : 
                selectedCn === w.id ? 'bg-pink-300 transform scale-105' : 'bg-white hover:bg-pink-50'
              }`}
            >
              {w.cn}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default MatchingGame;

import React, { useState, useMemo } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';
import { playSound } from '../utils/sounds';

interface SpellingBeeProps {
  onComplete: () => void;
}

const SpellingBee: React.FC<SpellingBeeProps> = ({ onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState<string[]>([]);
  const currentWord = WORD_LIST[currentIndex].en.toLowerCase();

  const letterOptions = useMemo(() => {
    const letters = currentWord.split('').filter(l => l !== ' ');
    const extras = 'abcdefghijklmnopqrstuvwxyz'.split('').sort(() => 0.5 - Math.random()).slice(0, 4);
    return [...letters, ...extras].sort(() => 0.5 - Math.random());
  }, [currentWord]);

  const handleLetterClick = (char: string) => {
    let nextInput = [...input];
    const targetWithSpaces = currentWord.split('');

    if (targetWithSpaces[nextInput.length] === ' ') {
      nextInput.push(' ');
    }

    const targetChar = targetWithSpaces[nextInput.length];
    if (char === targetChar) {
      playSound('correct');
      nextInput.push(char);
      setInput(nextInput);

      if (nextInput.join('') === currentWord) {
        setTimeout(() => {
          if (currentIndex < WORD_LIST.length - 1) {
            setCurrentIndex(c => c + 1);
            setInput([]);
          } else {
            onComplete();
          }
        }, 800);
      }
    } else {
      playSound('wrong');
    }
  };

  const handleCancel = (index: number) => {
    setInput(prev => prev.slice(0, index));
  };

  return (
    <div className="text-center p-4">
      <div className="flex justify-between items-center mb-8">
        <img src={POKEMON_SPRITES(POKEMON_IDS.Squirtle)} className="w-20 h-20" alt="Squirtle" />
        <h2 className="text-4xl font-bold text-blue-600">Spelling Bee 🐝</h2>
        <div className="text-2xl font-bold bg-white px-4 py-2 crayon-border">
          {currentIndex + 1} / {WORD_LIST.length}
        </div>
      </div>

      <div className="mb-8">
        <div className="text-4xl font-bold text-gray-700 mb-4">{WORD_LIST[currentIndex].cn}</div>
        <div className="text-6xl mb-4">{WORD_LIST[currentIndex].emoji}</div>
      </div>

      <div className="flex flex-wrap justify-center gap-2 mb-12 min-h-[80px]">
        {currentWord.split('').map((char, idx) => {
          const isSpace = char === ' ';
          const filled = input[idx];
          return (
            <div
              key={idx}
              onClick={() => filled && handleCancel(idx)}
              className={`w-12 h-16 flex items-center justify-center text-4xl font-bold crayon-border cursor-pointer transition-all ${
                isSpace ? 'border-none bg-transparent w-6' : 
                filled ? 'bg-yellow-200 animate-wiggle' : 'bg-gray-100'
              }`}
            >
              {filled !== ' ' ? filled : ''}
            </div>
          );
        })}
      </div>

      <div className="flex flex-wrap justify-center gap-4">
        {letterOptions.map((l, idx) => (
          <button
            key={idx}
            onClick={() => handleLetterClick(l)}
            className="w-16 h-16 bg-white text-3xl font-bold crayon-border hover:bg-blue-100 transform active:scale-90"
          >
            {l}
          </button>
        ))}
      </div>

      <p className="mt-8 text-gray-500 italic">Click a letter in the word to undo!</p>
    </div>
  );
};

export default SpellingBee;

