import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WORD_LIST, POKEMON_SPRITES, POKEMON_IDS } from '../constants';
import { playSound } from '../utils/sounds';

interface TugOfWarProps {
  onComplete: () => void;
}

const TugOfWar: React.FC<TugOfWarProps> = ({ onComplete }) => {
  const [round, setRound] = useState(0);
  const [team1Score, setTeam1Score] = useState(0); 
  const [team2Score, setTeam2Score] = useState(0);
  const [team1Index, setTeam1Index] = useState(0);
  const [team2Index, setTeam2Index] = useState(0);
  const [gameEnded, setGameEnded] = useState(false);
  const [winner, setWinner] = useState<number | null>(null);

  const team2TimerRef = useRef<NodeJS.Timeout | null>(null);

  // Groups of 5 words
  const roundWords = useMemo(() => {
    const start = round * 5;
    return WORD_LIST.slice(start, start + 5);
  }, [round]);

  const currentWordTeam1 = roundWords[team1Index];
  const currentWordTeam2 = roundWords[team2Index];

  // Random options for the current word
  const getOptions = (word: typeof WORD_LIST[0]) => {
    if (!word) return [];
    const others = WORD_LIST.filter(w => w.id !== word.id).sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...others, word].sort(() => 0.5 - Math.random());
  };

  const optionsTeam1 = useMemo(() => getOptions(currentWordTeam1), [currentWordTeam1]);
  const optionsTeam2 = useMemo(() => getOptions(currentWordTeam2), [currentWordTeam2]);

  // Computer Opponent Logic
  useEffect(() => {
    if (gameEnded) return;

    const startTeam2Turn = () => {
      // Computer answers every 3 to 5 seconds
      const delay = 3000 + Math.random() * 2000;
      team2TimerRef.current = setTimeout(() => {
        setTeam2Score(s => s + 1);
        setTeam2Index(i => {
          const next = i + 1;
          if (next >= 5) {
            checkGameOver(team1Score, team2Score + 1);
          }
          return Math.min(next, 4);
        });
        if (!gameEnded) startTeam2Turn();
      }, delay);
    };

    startTeam2Turn();
    return () => {
      if (team2TimerRef.current) clearTimeout(team2TimerRef.current);
    };
  }, [round, gameEnded]);

  const checkGameOver = (s1: number, s2: number) => {
    if (s1 >= 5 || s2 >= 5) {
      setGameEnded(true);
      setWinner(s1 >= 5 ? 1 : 2);
      setTimeout(() => {
        if ((round + 1) * 5 >= WORD_LIST.length) {
          onComplete();
        } else {
          // Reset for next round
          setRound(r => r + 1);
          setTeam1Score(0);
          setTeam2Score(0);
          setTeam1Index(0);
          setTeam2Index(0);
          setGameEnded(false);
          setWinner(null);
        }
      }, 2500);
    }
  };

  const handleSelectTeam1 = (wordId: string) => {
    if (gameEnded) return;

    if (wordId === currentWordTeam1.id) {
      playSound('correct');
      const newScore = team1Score + 1;
      setTeam1Score(newScore);
      setTeam1Index(i => {
        const next = i + 1;
        if (next >= 5) checkGameOver(newScore, team2Score);
        return Math.min(next, 4);
      });
    } else {
      playSound('wrong');
    }
  };

  // Rope position calculation
  // The center is 0. Difference in scores pulls it.
  const ropePosition = (team1Score - team2Score) * 35;

  return (
    <div className="flex flex-col h-full select-none relative">
      <div className="text-center mb-4">
        <h2 className="text-4xl font-black text-blue-600 tracking-widest uppercase">Tug of War Competition</h2>
        <p className="text-gray-400 font-bold">Solve 5 words faster than the computer to win!</p>
      </div>

      <div className="flex flex-1 gap-4 items-stretch h-[550px]">
        {/* Team 1 Panel (Blue) */}
        <div className="flex-1 bg-blue-50/50 rounded-3xl border-4 border-blue-400 flex flex-col items-center p-6 relative">
          <div className="bg-blue-400 text-white px-8 py-1 rounded-full font-bold text-xl mb-6 shadow-md">TEAM 1 (YOU)</div>

          <div className="mb-6 text-center w-full">
            <div className="text-sm font-bold text-blue-400 mb-2 uppercase tracking-tighter">Word {team1Index + 1} of 5</div>
            <div className="text-6xl font-black text-blue-600 bg-white px-6 py-4 rounded-2xl shadow-lg border-2 border-blue-100 min-h-[120px] flex items-center justify-center">
              {currentWordTeam1?.cn}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3 w-full">
            {optionsTeam1.map((opt) => (
              <button
                key={opt.id}
                onClick={() => handleSelectTeam1(opt.id)}
                className="p-4 text-xl font-black bg-white border-2 border-blue-200 rounded-2xl hover:bg-blue-100 hover:border-blue-400 transition-all shadow-sm active:scale-95 text-gray-700 min-h-[80px]"
              >
                {opt.en}
              </button>
            ))}
          </div>

          <div className="mt-auto bg-blue-100/50 px-6 py-2 rounded-full font-black text-blue-600 text-2xl">
            SCORE: {team1Score}
          </div>
        </div>

        {/* Competition Area (Center) */}
        <div className="w-80 bg-gray-50 rounded-3xl border-4 border-dashed border-gray-200 flex flex-col items-center justify-center p-4 relative overflow-hidden">
           {/* Timer/Round */}
           <div className="absolute top-4 text-gray-400 font-black text-xl bg-white px-4 py-1 rounded-full shadow-sm border border-gray-100">
              ROUND {round + 1}
           </div>

           {/* Central Line */}
           <div className="absolute top-0 bottom-0 left-1/2 w-1 border-l-4 border-dashed border-gray-300 -translate-x-1/2"></div>

           {/* The Rope and Characters */}
           <div className="relative w-full h-full flex items-center justify-center">
              {/* Rope */}
              <div 
                className="absolute w-[200%] h-3 bg-amber-900/80 rounded-full shadow-md z-10 transition-transform duration-500 ease-out" 
                style={{ transform: `translateX(${ropePosition}px)` }}
              >
                 {/* Rope Flag */}
