}

const TugOfWar: React.FC<TugOfWarProps> = ({ onComplete }) => {
  const [round, setRound] = useState(0);
  const [team1Score, setTeam1Score] = useState(0); 
  const [team2Score, setTeam2Score] = useState(0);
  const [team1Index, setTeam1Index] = useState(0);
  const [team2Index, setTeam2Index] = useState(0);
  const [gameEnded, setGameEnded] = useState(false);
  const [winner, setWinner] = useState<number | null>(null);

  // Fix: Use ReturnType<typeof setTimeout> instead of NodeJS.Timeout to avoid namespace issues in browser environment
  const team2TimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Groups of 5 words
  const roundWords = useMemo(() => {
    const start = round * 5;
    return WORD_LIST.slice(start, start + 5);
  }, [round]);

  const currentWordTeam1 = roundWords[team1Index];
  const currentWordTeam2 = roundWords[team2Index];

  // Random options for the current word
  const getOptions = (word: typeof WORD_LIST[0]) => {
    if (!word) return [];
    const others = WORD_LIST.filter(w => w.id !== word.id).sort(() => 0.5 - Math.random()).slice(0, 3);
    return [...others, word].sort(() => 0.5 - Math.random());
  };

  const optionsTeam1 = useMemo(() => getOptions(currentWordTeam1), [currentWordTeam1]);
  const optionsTeam2 = useMemo(() => getOptions(currentWordTeam2), [currentWordTeam2]);

  // Computer Opponent Logic
  useEffect(() => {
    if (gameEnded) return;

    const startTeam2Turn = () => {
      // Computer answers every 3 to 5 seconds
      const delay = 3000 + Math.random() * 2000;
      team2TimerRef.current = setTimeout(() => {
        setTeam2Score(s => s + 1);
        setTeam2Index(i => {
          const next = i + 1;
          if (next >= 5) {
            checkGameOver(team1Score, team2Score + 1);
          }
          return Math.min(next, 4);
        });
        if (!gameEnded) startTeam2Turn();
      }, delay);
    };

    startTeam2Turn();
    return () => {
      if (team2TimerRef.current) clearTimeout(team2TimerRef.current);
    };
  }, [round, gameEnded]);

  const checkGameOver = (s1: number, s2: number) => {
    if (s1 >= 5 || s2 >= 5) {
      setGameEnded(true);
      setWinner(s1 >= 5 ? 1 : 2);
      setTimeout(() => {
        if ((round + 1) * 5 >= WORD_LIST.length) {
          onComplete();
        } else {
          // Reset for next round
          setRound(r => r + 1);
          setTeam1Score(0);
          setTeam2Score(0);
          setTeam1Index(0);
          setTeam2Index(0);
          setGameEnded(false);
          setWinner(null);
        }
      }, 2500);
    }
  };

  const handleSelectTeam1 = (wordId: string) => {
    if (gameEnded) return;

    if (wordId === currentWordTeam1.id) {
      playSound('correct');
      const newScore = team1Score + 1;
      setTeam1Score(newScore);
      setTeam1Index(i => {
        const next = i + 1;
        if (next >= 5) checkGameOver(newScore, team2Score);
        return Math.min(next, 4);
      });
    } else {
      playSound('wrong');
    }
  };

  // Rope position calculation
  // The center is 0. Difference in scores pulls it.
  const ropePosition = (team1Score - team2Score) * 35;

  return (
    <div className="flex flex-col h-full select-none relative">
