              {currentWordTeam1?.cn}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3 w-full">
            {optionsTeam1.map((opt) => (
              <button
                key={opt.id}
                onClick={() => handleSelectTeam1(opt.id)}
                className="p-4 text-xl font-black bg-white border-2 border-blue-200 rounded-2xl hover:bg-blue-100 hover:border-blue-400 transition-all shadow-sm active:scale-95 text-gray-700 min-h-[80px]"
              >
                {opt.en}
              </button>
            ))}
          </div>

          <div className="mt-auto bg-blue-100/50 px-6 py-2 rounded-full font-black text-blue-600 text-2xl">
            SCORE: {team1Score}
          </div>
